import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"29. Payment Of Wages Allowances Employee Records And","description":"","frontmatter":{"title":"29. Payment Of Wages Allowances Employee Records And","eba":"Mental Health Services 2024-2028","topics":["allowances","wages"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/wages/29-payment-of-wages-allowances-employee-records-and.md","filePath":"ebas/mental-health/common-terms/wages/29-payment-of-wages-allowances-employee-records-and.md"}'),r={name:"ebas/mental-health/common-terms/wages/29-payment-of-wages-allowances-employee-records-and.md"};function s(l,e,i,p,m,c){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_29-payment-of-wages-allowances-employee-records-and" tabindex="-1">29. Payment Of Wages Allowances Employee Records And <a class="header-anchor" href="#_29-payment-of-wages-allowances-employee-records-and" aria-label="Permalink to &quot;29. Payment Of Wages Allowances Employee Records And&quot;">​</a></h1><p>Related Matters</p><p><strong>29.1</strong> Wages and allowances The weekly wage rates and allowance rates provided for by this Agreement are set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>, including applicable increases.</p><p><strong>29.2</strong> Overlapping Pay Points Between Grades Where an Employee moves from one grade to a higher grade and the pay rates are less, the Employee will be paid at the next yearly increment level upon appointment to the new grade. For example, where a RPN 2 Advanced/Psych Clinical Specialist moves to an RPN 3 they will commence at the Year 2 rate.</p><p><strong>29.3</strong> Payment Each Employee&#39;s wages will be paid fortnightly into the Employee&#39;s nominated account by electronic funds transfer, or other method determined by mutual agreement, and no later than Thursday following the end of the pay period.</p><p><strong>29.4</strong> Employee Records</p><p><strong>(a)</strong> Payslip</p><p><strong>(i)</strong> The Act and FW Regulations set out an Employer&#39;s obligations with respect to pay slips, including but not limited to a requirement to specify in writing: <strong>(A)</strong> the period to which the pay slip relates <strong>(B)</strong> the amount of wages to which the Employee is entitled <strong>(C)</strong> if an amount was deducted from the gross amount of the payment, the name or the name and number of the fund or account into which the deduction was paid; and <strong>(D)</strong> the net amount for each payment.</p><p><strong>(b)</strong> To the extent reasonably practicable, payslips will record an Employee&#39;s accrued annual leave and personal leave.</p><p><strong>(c)</strong> Employee Records</p><p><strong>(i)</strong> The Act and FW Regulations set out an Employer&#39;s obligations with respect to record keeping including but not limited to: <strong>(A)</strong> a requirement to keep a record that sets out any leave the employee takes and the balance (if any) of the employee&#39;s entitlement to that leave from time to time <strong>(B)</strong> the inspection and copying of an employee record by the employee or former employee to whom the record relates <strong>(C)</strong> the requirement to keep accurate employee records.</p><p><strong>(d)</strong> Copying and Inspection of Record</p><p>After receiving a request from an Employee (or former Employee) for a copy or inspection of their Employee record, the Employer must:</p><p><strong>(i)</strong> If the Employee record is kept at the premises (including electronically) (where available)) at which the Employee works:</p><p><strong>(A)</strong> Make the copy available to the Employee at the premises within 3 business days, or <strong>(B)</strong> Post a copy to the Employee within 14 days after receiving the request, or <strong>(C)</strong> Provide a copy electronically to the Employee upon request, where available.</p><p><strong>(ii)</strong> If the Employee record is not kept at the premises at which the Employee works, as soon as practicable after receiving the request:</p><p><strong>(A)</strong> Make the copy available to the Employee at the premises; or <strong>(B)</strong> Post a copy of the Employee record to the Employee or former Employee; or <strong>(C)</strong> Provide a copy electronically to the Employee upon request, where available.</p><p><strong>(e)</strong> For the purpose of this clause, an Employee record includes: <strong>(A)</strong> Any documents or information prescribed by the Act or the FW Regulations <strong>(B)</strong> Any leave that the Employee takes; and <strong>(C)</strong> The balance (if any) of the Employee’s entitlement to that leave from time to time.</p><p><strong>29.5</strong> Payment on termination</p><p><strong>(a)</strong> When an Employee&#39;s employment has been terminated by the Employer with notice, payment of all wages and other monies owing to an Employee will be made to the Employee on or before the final day of work of the Employee.</p><p><strong>(b)</strong> Where the Employer terminates the Employee&#39;s employment without notice, payment of all wages and other monies owing to the Employee will made to the Employee within two business days.</p><p><strong>(c)</strong> When notice of termination of employment has been given by an Employee, payment of all wages and other monies owing to an Employee will be made as soon as practicable but not later than the ordinary pay day following the end of employment.</p><p><strong>29.6</strong> Biometric Timekeeping Where an Employer has or introduces biometric timekeeping, the Employer will give consideration to an Employee with genuine difficulties in complying with a requirement to utilise biometric technology to mitigate or avert the impact on that Employee.</p>',23)])])}const g=t(r,[["render",s]]);export{y as __pageData,g as default};
